import type { ScheduledLessonDto } from '@soenglish/shared-types';

type ConflictStrategy = 'any-overlap' | 'same-teacher-overlap';

function toMinutes(time: string): number {
  const [hour, minute] = time.split(':').map(Number);
  return hour * 60 + minute;
}

export function hasTimeConflict(
  lessons: ScheduledLessonDto[],
  candidate: ScheduledLessonDto,
  ignoreLessonId?: string,
  strategy: ConflictStrategy = 'any-overlap',
): boolean {
  const candidateStart = toMinutes(candidate.startTime);
  const candidateEnd = toMinutes(candidate.endTime);
  return lessons
    .filter((lesson) => lesson.date === candidate.date && lesson.id !== ignoreLessonId)
    .filter((lesson) =>
      strategy === 'same-teacher-overlap' ? lesson.teacherId === candidate.teacherId : true,
    )
    .some((lesson) => {
      const lessonStart = toMinutes(lesson.startTime);
      const lessonEnd = toMinutes(lesson.endTime);
      return candidateStart < lessonEnd && candidateEnd > lessonStart;
    });
}

export function isPastSlot(date: string, time: string): boolean {
  const at = new Date(`${date}T${time}:00`);
  return at.getTime() < Date.now();
}

